using System.ComponentModel.DataAnnotations;

namespace sv_dff1d634315d4601ba2e36af4ce77fd7.Models;

public class ReviewModel
{
    [Required(ErrorMessage = "Product name is required.")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title cannot exceed 100 characters.")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body cannot exceed 2000 characters.")]
    public string ReviewBody { get; set; } = string.Empty;
}

namespace sv_dff1d634315d4601ba2e36af4ce77fd7.Services;

public class ReviewValidationResult
{
    public bool IsValid { get; set; } = true;
    public Dictionary<string, string> FieldErrors { get; set; } = new();
}

public class ReviewService
{
    /// <summary>
    /// Validates and submits a review. Returns field-specific errors if validation fails.
    /// </summary>
    public Task<ReviewValidationResult> ValidateAndSubmitAsync(
        string productName, int rating, string reviewTitle, string reviewBody, List<string> photoFileNames)
    {
        var result = new ReviewValidationResult();

        // Simulate server-side profanity check: reject titles containing "spam"
        if (reviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            result.IsValid = false;
            result.FieldErrors[nameof(Models.ReviewModel.ReviewTitle)] =
                "Review title contains inappropriate language.";
        }

        // Additional server-side rules can be added here

        return Task.FromResult(result);
    }
}

@page "/write-review"
@rendermode InteractiveServer
@using sv_dff1d634315d4601ba2e36af4ce77fd7.Models
@using sv_dff1d634315d4601ba2e36af4ce77fd7.Services
@inject ReviewService ReviewService

<PageTitle>Write a Review</PageTitle>

<h3>Write a Review</h3>

@if (submitted)
{
    <div class="alert alert-success" role="alert">
        <h4>Thank you!</h4>
        <p>Your review has been submitted successfully.</p>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="write-review">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="productName" class="form-label">Product Name</label>
            <InputText id="productName" class="form-control" @bind-Value="model.ProductName" />
            <ValidationMessage For="() => model.ProductName" />
            @if (serverErrors.ContainsKey(nameof(model.ProductName)))
            {
                <div class="text-danger">@serverErrors[nameof(model.ProductName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="rating" class="form-label">Rating (1–5)</label>
            <InputNumber id="rating" class="form-control" @bind-Value="model.Rating" />
            <ValidationMessage For="() => model.Rating" />
            @if (serverErrors.ContainsKey(nameof(model.Rating)))
            {
                <div class="text-danger">@serverErrors[nameof(model.Rating)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewTitle" class="form-label">Review Title</label>
            <InputText id="reviewTitle" class="form-control" @bind-Value="model.ReviewTitle" />
            <ValidationMessage For="() => model.ReviewTitle" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewTitle)))
            {
                <div class="text-danger">@serverErrors[nameof(model.ReviewTitle)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewBody" class="form-label">Review Body</label>
            <InputTextArea id="reviewBody" class="form-control" rows="5" @bind-Value="model.ReviewBody" />
            <ValidationMessage For="() => model.ReviewBody" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewBody)))
            {
                <div class="text-danger">@serverErrors[nameof(model.ReviewBody)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="photos" class="form-label">Upload Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile id="photos" class="form-control" OnChange="OnFilesSelected" multiple accept=".jpg,.jpeg,.png" />
            @if (!string.IsNullOrEmpty(photoError))
            {
                <div class="text-danger">@photoError</div>
            }
            @if (selectedFiles.Count > 0)
            {
                <ul class="list-unstyled mt-2">
                    @foreach (var file in selectedFiles)
                    {
                        <li>@file.Name — @FormatFileSize(file.Size)</li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Review</span>
            }
        </button>
    </EditForm>
}

@code {
    private ReviewModel model = new();
    private List<IBrowserFile> selectedFiles = new();
    private Dictionary<string, string> serverErrors = new();
    private string? photoError;
    private bool submitted;
    private bool isSubmitting;

    private const int MaxFiles = 3;
    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB

    private void OnFilesSelected(InputFileChangeEventArgs e)
    {
        photoError = null;
        var files = e.GetMultipleFiles(MaxFiles + 1);

        if (files.Count > MaxFiles)
        {
            photoError = $"You can upload a maximum of {MaxFiles} photos.";
            return;
        }

        var allowedTypes = new[] { "image/jpeg", "image/png" };
        foreach (var file in files)
        {
            if (!allowedTypes.Contains(file.ContentType))
            {
                photoError = $"'{file.Name}' is not a valid image type. Only JPG and PNG are allowed.";
                return;
            }
            if (file.Size > MaxFileSize)
            {
                photoError = $"'{file.Name}' exceeds the 5 MB size limit.";
                return;
            }
        }

        selectedFiles = files.ToList();
    }

    private async Task HandleSubmit()
    {
        serverErrors.Clear();
        isSubmitting = true;

        try
        {
            var photoNames = selectedFiles.Select(f => f.Name).ToList();
            var result = await ReviewService.ValidateAndSubmitAsync(
                model.ProductName, model.Rating!.Value, model.ReviewTitle, model.ReviewBody, photoNames);

            if (!result.IsValid)
            {
                serverErrors = result.FieldErrors;
                return;
            }

            // In a real app, read file streams and persist them here.
            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private static string FormatFileSize(long bytes)
    {
        if (bytes < 1024) return $"{bytes} B";
        if (bytes < 1024 * 1024) return $"{bytes / 1024.0:F1} KB";
        return $"{bytes / (1024.0 * 1024.0):F2} MB";
    }
}

